/**
 * 命令行番茄钟 — 25 分钟专注 + 5 分钟休息的循环计时器。
 *
 * 用法:
 *   node pomodoro.mjs                    默认设置
 *   node pomodoro.mjs -w 30 -b 10        专注 30min，休息 10min
 *   node pomodoro.mjs -c 4               完成 4 个番茄后自动停止
 *   node pomodoro.mjs -t "写报告"         指定任务名称
 *   node pomodoro.mjs --stats            查看历史统计
 *
 * 运行时按键:
 *   p / Space    暂停 / 继续
 *   s            跳过当前阶段
 *   q            退出
 */

import { readFileSync, writeFileSync, existsSync } from "fs";
import { spawn } from "child_process";
import { createInterface } from "readline";
import { fileURLToPath } from "url";
import { dirname, join } from "path";
import { parseArgs } from "util";

// ── 常量 ──────────────────────────────────────────────────────
const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_FILE = join(__dirname, ".pomodoro_data.json");

const DEFAULT_WORK_MIN = 25;
const DEFAULT_BREAK_MIN = 5;
const DEFAULT_LONG_BREAK_MIN = 15;
const CYCLES_BEFORE_LONG_BREAK = 4;

// ANSI 控制序列
const CLEAR_LINE = "\x1b[2K";
const CURSOR_UP = "\x1b[A";
const HIDE_CURSOR = "\x1b[?25l";
const SHOW_CURSOR = "\x1b[?25h";

const RED = "\x1b[91m";
const GREEN = "\x1b[92m";
const YELLOW = "\x1b[93m";
const BLUE = "\x1b[94m";
const MAGENTA = "\x1b[95m";
const CYAN = "\x1b[96m";
const BOLD = "\x1b[1m";
const DIM = "\x1b[2m";
const RESET = "\x1b[0m";

// ── 键盘输入（非阻塞） ─────────────────────────────────────────
let keyBuffer = [];

function startKeyListener() {
  // 切换到 raw mode，逐字符读取
  if (process.stdin.isTTY) {
    process.stdin.setRawMode(true);
  }
  process.stdin.resume();
  process.stdin.on("data", (chunk) => {
    for (const b of chunk) {
      // 只接收可打印 ASCII 和常见控制字符
      const c = String.fromCharCode(b);
      if (b === 3) {
        // Ctrl+C
        process.stdout.write(SHOW_CURSOR);
        process.stdout.write("\n  已退出\n");
        process.exit(0);
      }
      keyBuffer.push(c.toLowerCase());
    }
  });
}

function stopKeyListener() {
  if (process.stdin.isTTY) {
    process.stdin.setRawMode(false);
  }
  process.stdin.pause();
}

function readKey() {
  if (keyBuffer.length > 0) {
    return keyBuffer.shift();
  }
  return null;
}

// ── 音频通知 ──────────────────────────────────────────────────
function beep() {
  if (process.platform === "win32") {
    spawn("powershell", ["-NoProfile", "-Command", "[System.Console]::Beep(800,200); [System.Console]::Beep(800,200); [System.Console]::Beep(800,400)"], { stdio: "ignore" });
  } else {
    process.stdout.write("\x07");
  }
}

// ── 数据持久化 ────────────────────────────────────────────────
function loadData() {
  if (existsSync(DATA_FILE)) {
    return JSON.parse(readFileSync(DATA_FILE, "utf-8"));
  }
  return { sessions: [] };
}

function saveSession(workMin, task, completed) {
  const data = loadData();
  const now = new Date();
  data.sessions.push({
    date: now.toISOString().slice(0, 10),
    time: now.toTimeString().slice(0, 8),
    duration_min: workMin,
    task,
    completed,
  });
  // 保留最近 500 条
  if (data.sessions.length > 500) {
    data.sessions = data.sessions.slice(-500);
  }
  writeFileSync(DATA_FILE, JSON.stringify(data, null, 2));
}

function showStats() {
  const data = loadData();
  const sessions = data.sessions;
  if (sessions.length === 0) {
    console.log(`\n  暂无番茄记录，开始你的第一个番茄吧!\n`);
    return;
  }

  const today = new Date().toISOString().slice(0, 10);
  const todaySessions = sessions.filter((s) => s.date === today);
  const completed = sessions.filter((s) => s.completed);
  const totalFocusMin = completed.reduce((sum, s) => sum + s.duration_min, 0);
  const todayCompleted = todaySessions.filter((s) => s.completed);

  console.log();
  console.log(`  ${BOLD}番茄统计${RESET}`);
  console.log(`  ${"─".repeat(36)}`);
  console.log(`  今日完成: ${GREEN}${todayCompleted.length}${RESET} 个番茄`);
  console.log(`  今日专注: ${GREEN}${todayCompleted.reduce((s, i) => s + i.duration_min, 0)}${RESET} 分钟`);
  console.log(`  历史完成: ${GREEN}${completed.length}${RESET} 个番茄`);
  console.log(`  历史专注: ${GREEN}${totalFocusMin}${RESET} 分钟 (${(totalFocusMin / 60).toFixed(1)} 小时)`);
  console.log(`  ${"─".repeat(36)}`);

  if (todaySessions.length > 0) {
    console.log();
    console.log(`  ${BOLD}今日记录${RESET}`);
    for (const s of todaySessions.reverse()) {
      const icon = s.completed ? "✓" : "✗";
      const color = s.completed ? GREEN : DIM;
      const taskStr = s.task ? ` — ${s.task}` : "";
      console.log(`  ${color}${icon} ${s.time}  ${s.duration_min}min${taskStr}${RESET}`);
    }
  }
  console.log();
}

// ── 辅助 ──────────────────────────────────────────────────────
function formatTime(seconds) {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
}

function progressBar(current, total, width = 30) {
  const ratio = total > 0 ? current / total : 0;
  const filled = Math.round(width * ratio);
  const bar = "█".repeat(filled) + "░".repeat(width - filled);
  const pct = Math.round(ratio * 100);
  return `[${bar}] ${pct}%`;
}

function prompt(question) {
  return new Promise((resolve) => {
    const rl = createInterface({ input: process.stdin, output: process.stdout });
    // raw mode 会干扰 readline，先临时恢复
    const wasRaw = process.stdin.isRaw;
    if (wasRaw) process.stdin.setRawMode(false);
    rl.question(question, (answer) => {
      rl.close();
      if (wasRaw) process.stdin.setRawMode(true);
      resolve(answer.trim());
    });
  });
}

// ── 倒计时核心 ────────────────────────────────────────────────
function countdown(totalSeconds, label, color) {
  let remaining = totalSeconds;
  let paused = false;

  return new Promise((resolve) => {
    function tick() {
      // 检查按键
      while (true) {
        const key = readKey();
        if (key === null) break;

        if (key === "p" || key === " ") {
          paused = !paused;
          if (paused) {
            process.stdout.write(`\n  ${YELLOW}⏸  已暂停 — 按 p 继续${RESET}`);
          } else {
            process.stdout.write(`${CURSOR_UP}${CLEAR_LINE}\r`);
          }
        } else if (key === "s") {
          process.stdout.write(`\n  ${YELLOW}⏭  已跳过${RESET}`);
          return resolve(false);
        } else if (key === "q") {
          process.stdout.write(`${SHOW_CURSOR}\n  ${RED}✕  已退出${RESET}\n`);
          process.exit(0);
        }
      }

      // 渲染
      process.stdout.write(
        `${CLEAR_LINE}\r  ${color}${BOLD}${label}${RESET}  ` +
        `${formatTime(remaining)}  ` +
        `${progressBar(totalSeconds - remaining, totalSeconds)}`
      );

      if (remaining <= 0) {
        resolve(true);
        return;
      }

      if (paused) {
        setTimeout(tick, 100);
        return;
      }

      remaining--;
      setTimeout(tick, 1000);
    }

    tick();
  });
}

// ── 主流程 ────────────────────────────────────────────────────
async function run(opts) {
  const workSec = opts.work * 60;
  const breakSec = opts.breakMin * 60;
  const longBreakSec = opts.longBreak * 60;
  const maxCycles = opts.cycles;

  let task = opts.task;
  if (!task) {
    console.log();
    task = await prompt(`  ${CYAN}任务名称 (可留空): ${RESET}`);
  }

  console.log();
  console.log(
    `  ${DIM}专注 ${opts.work}min · 休息 ${opts.breakMin}min · ` +
    `长休息 ${opts.longBreak}min (每 ${CYCLES_BEFORE_LONG_BREAK} 轮)${RESET}`
  );
  console.log(`  ${DIM}按 p 暂停 · s 跳过 · q 退出${RESET}\n`);

  startKeyListener();
  process.stdout.write(HIDE_CURSOR);

  let cycle = 0;
  let completedCycles = 0;

  try {
    while (maxCycles === 0 || cycle < maxCycles) {
      cycle++;

      // ── 专注阶段 ──
      console.log(`  ${BOLD}🍅 第 ${cycle} 个番茄${RESET}  ${DIM}${task}${RESET}`);
      const finished = await countdown(workSec, "专注", RED);

      if (finished) {
        completedCycles++;
        saveSession(opts.work, task, true);
        process.stdout.write(`${CLEAR_LINE}\r  ${GREEN}✓ 专注完成！${RESET}\n`);
        beep();
      } else {
        saveSession(opts.work, task, false);
        console.log();
      }

      if (maxCycles > 0 && cycle >= maxCycles) {
        break;
      }

      // ── 休息阶段 ──
      if (finished) {
        const isLong = cycle % CYCLES_BEFORE_LONG_BREAK === 0;
        if (isLong) {
          console.log(`  ${MAGENTA}☕ 长休息 ${opts.longBreak}min${RESET}`);
          await countdown(longBreakSec, "休息", GREEN);
        } else {
          console.log(`  ${CYAN}☕ 休息 ${opts.breakMin}min${RESET}`);
          await countdown(breakSec, "休息", GREEN);
        }
        process.stdout.write(`${CLEAR_LINE}\r  ${GREEN}✓ 休息结束，准备下一个番茄！${RESET}\n`);
        beep();
        console.log();
      }
    }
  } finally {
    stopKeyListener();
    process.stdout.write(SHOW_CURSOR);
  }

  // ── 总结 ──
  console.log();
  console.log(`  ${BOLD}本轮总结${RESET}`);
  console.log(`  ${"─".repeat(24)}`);
  console.log(`  完成番茄: ${GREEN}${completedCycles}${RESET}`);
  console.log(`  总专注:   ${GREEN}${completedCycles * opts.work}${RESET} 分钟`);
  console.log();
}

// ── 入口 ──────────────────────────────────────────────────────
const usage = `
用法:
  node pomodoro.mjs                      默认 25min 专注 + 5min 休息
  node pomodoro.mjs -w 45 -b 10          45min 专注 + 10min 休息
  node pomodoro.mjs -t "写报告"           指定任务名称
  node pomodoro.mjs -c 4                 完成 4 个番茄后停止
  node pomodoro.mjs --stats              查看历史统计

选项:
  -w, --work       专注时长（分钟），默认 25
  -b, --break-min  短休息时长（分钟），默认 5
  -l, --long-break 长休息时长（分钟），默认 15
  -c, --cycles     番茄轮数，0 表示无限循环
  -t, --task       任务名称
  --stats          显示历史统计

运行时按键:
  p / Space    暂停/继续
  s            跳过当前阶段
  q / Ctrl+C   退出
`;

const opts = { work: DEFAULT_WORK_MIN, breakMin: DEFAULT_BREAK_MIN, longBreak: DEFAULT_LONG_BREAK_MIN, cycles: 0, task: "", stats: false, help: false };

// 参数解析
let args;
try {
  args = parseArgs({
    options: {
      work:     { type: "string", short: "w" },
      "break-min": { type: "string", short: "b" },
      "long-break": { type: "string", short: "l" },
      cycles:   { type: "string", short: "c" },
      task:     { type: "string", short: "t" },
      stats:    { type: "boolean" },
      help:     { type: "boolean", short: "h" },
    },
    allowPositionals: true,
  });
} catch {
  // 无法解析时回退手动解析
  args = { values: {} };
}

if (args.values.help) {
  console.log(usage);
  process.exit(0);
}

if (args.values.work)     opts.work = parseInt(args.values.work, 10);
if (args.values["break-min"]) opts.breakMin = parseInt(args.values["break-min"], 10);
if (args.values["long-break"]) opts.longBreak = parseInt(args.values["long-break"], 10);
if (args.values.cycles)   opts.cycles = parseInt(args.values.cycles, 10);
if (args.values.task)     opts.task = args.values.task;
if (args.values.stats)    opts.stats = true;

// 校验
for (const [name, val] of [["专注时长", opts.work], ["休息时长", opts.breakMin], ["长休息时长", opts.longBreak]]) {
  if (val < 1 || val > 120) {
    console.error(`错误: ${name}必须在 1-120 分钟之间`);
    process.exit(1);
  }
}

if (opts.stats) {
  showStats();
} else {
  run(opts);
}

