        saveSession(opts.work, task, true);
        process.stdout.write(`${CLEAR_LINE}\r  ${GREEN}✓ 专注完成！${RESET}\n`);
        beep();
      } else {
        saveSession(opts.work, task, false);
        console.log();
      }

      if (maxCycles > 0 && cycle >= maxCycles) {
        break;
      }

      // ── 休息阶段 ──
      if (finished) {
        const isLong = cycle % CYCLES_BEFORE_LONG_BREAK === 0;
        if (isLong) {
          console.log(`  ${MAGENTA}☕ 长休息 ${opts.longBreak}min${RESET}`);
          await countdown(longBreakSec, "休息", GREEN);
        } else {
          console.log(`  ${CYAN}☕ 休息 ${opts.breakMin}min${RESET}`);
          await countdown(breakSec, "休息", GREEN);
        }
        process.stdout.write(`${CLEAR_LINE}\r  ${GREEN}✓ 休息结束，准备下一个番茄！${RESET}\n`);
        beep();
        console.log();
      }
    }
  } finally {
    stopKeyListener();
    process.stdout.write(SHOW_CURSOR);
  }

  // ── 总结 ──
  console.log();
  console.log(`  ${BOLD}本轮总结${RESET}`);
  console.log(`  ${"─".repeat(24)}`);
  console.log(`  完成番茄: ${GREEN}${completedCycles}${RESET}`);
  console.log(`  总专注:   ${GREEN}${completedCycles * opts.work}${RESET} 分钟`);
  console.log();
}

// ── 入口 ──────────────────────────────────────────────────────
const usage = `
用法:
  node pomodoro.mjs                      默认 25min 专注 + 5min 休息
  node pomodoro.mjs -w 45 -b 10          45min 专注 + 10min 休息
  node pomodoro.mjs -t "写报告"           指定任务名称
  node pomodoro.mjs -c 4                 完成 4 个番茄后停止
  node pomodoro.mjs --stats              查看历史统计

选项:
  -w, --work       专注时长（分钟），默认 25
  -b, --break-min  短休息时长（分钟），默认 5
  -l, --long-break 长休息时长（分钟），默认 15
  -c, --cycles     番茄轮数，0 表示无限循环
  -t, --task       任务名称
  --stats          显示历史统计

运行时按键:
  p / Space    暂停/继续
  s            跳过当前阶段
  q / Ctrl+C   退出
`;

const opts = { work: DEFAULT_WORK_MIN, breakMin: DEFAULT_BREAK_MIN, longBreak: DEFAULT_LONG_BREAK_MIN, cycles: 0, task: "", stats: false, help: false };

// 参数解析
let args;
try {
  args = parseArgs({
    options: {
      work:     { type: "string", short: "w" },
      "break-min": { type: "string", short: "b" },
      "long-break": { type: "string", short: "l" },
      cycles:   { type: "string", short: "c" },
      task:     { type: "string", short: "t" },
      stats:    { type: "boolean" },
      help:     { type: "boolean", short: "h" },
    },
    allowPositionals: true,
  });
} catch {
  // 无法解析时回退手动解析
  args = { values: {} };
}

if (args.values.help) {
  console.log(usage);
  process.exit(0);
}

if (args.values.work)     opts.work = parseInt(args.values.work, 10);
if (args.values["break-min"]) opts.breakMin = parseInt(args.values["break-min"], 10);
if (args.values["long-break"]) opts.longBreak = parseInt(args.values["long-break"], 10);
if (args.values.cycles)   opts.cycles = parseInt(args.values.cycles, 10);
if (args.values.task)     opts.task = args.values.task;
if (args.values.stats)    opts.stats = true;

// 校验
for (const [name, val] of [["专注时长", opts.work], ["休息时长", opts.breakMin], ["长休息时长", opts.longBreak]]) {
  if (val < 1 || val > 120) {
    console.error(`错误: ${name}必须在 1-120 分钟之间`);
    process.exit(1);
  }
}

if (opts.stats) {
  showStats();
} else {
  run(opts);
}
